//! Delegated Prover Server for zk-X509.
//!
//! Service operators deploy this server to generate ZK proofs on behalf of users.
//! The user sends pre-signed data (cert + signatures + consent); this server runs
//! the SP1 prover and returns the proof. The user's private key never reaches
//! this server — only signatures generated by the OS keychain are transmitted.
//!
//! Usage:
//!   RUST_LOG=info cargo run --release --bin prover-server
//!
//! Environment:
//!   PROVER_URL     - This server's public URL (for consent verification)
//!   PROVER_PORT    - Port to listen on (default: 9090)
//!   PROVER_LOG_DIR - Directory for compliance logs (default: ./logs)
//!
//! Endpoints:
//!   POST /api/prove  - Generate a ZK proof from pre-signed inputs
//!   GET  /api/health - Server status (SP1 version, Docker availability)

use axum::{
    extract::Json,
    http::StatusCode,
    routing::{get, post},
    Router,
};
use serde::{Deserialize, Serialize};
use sha2::{Digest, Sha256};
use sp1_sdk::{
    blocking::{ProveRequest, Prover, ProverClient},
    include_elf, Elf, SP1ProofWithPublicValues,
};
use std::time::{Instant, SystemTime, UNIX_EPOCH};
use tower_http::cors::{AllowOrigin, CorsLayer};

const ZK_X509_ELF: Elf = include_elf!("zk-x509-program");
const CONSENT_DOMAIN: &str = "zk-x509-delegated-proving-consent";

// ── Request / Response ──────────────────────────────────────────

#[derive(Deserialize)]
struct DelegatedProveRequest {
    consent_signature: String,
    cert_der: String,            // base64
    cert_chain: Vec<String>,     // base64[]
    ownership_sig: String,       // hex
    nullifier_sig: String,       // hex
    registrant: String,          // 0x address
    wallet_index: u32,
    max_wallets: u32,
    disclosure_mask: u8,
    chain_id: u64,
    registry_address: String,    // 0x address
    ca_merkle_root: String,      // 0x hex
    ca_merkle_proof: Vec<String>,// 0x hex[]
    #[serde(default)]
    crl_data: Option<String>,    // base64, optional
    #[serde(default)]
    _crl_merkle_root: Option<String>,
    timestamp: u64,
}

#[derive(Serialize)]
struct ProveResponse {
    proof: String,
    public_values: String,
    proving_time_ms: u64,
}

#[derive(Serialize)]
struct HealthResponse {
    status: String,
    sp1_version: String,
    prover_url: String,
}

#[derive(Serialize)]
struct ErrorResponse {
    error: String,
}

// ── Helpers ──────────────────────────────────────────────────────

fn decode_hex(s: &str) -> Result<Vec<u8>, String> {
    let s = s.strip_prefix("0x").unwrap_or(s);
    hex::decode(s).map_err(|e| format!("Invalid hex: {}", e))
}

fn decode_base64(s: &str) -> Result<Vec<u8>, String> {
    use base64::Engine;
    base64::engine::general_purpose::STANDARD
        .decode(s)
        .map_err(|e| format!("Invalid base64: {}", e))
}

fn decode_hash(s: &str) -> Result<[u8; 32], String> {
    let bytes = decode_hex(s)?;
    if bytes.len() != 32 {
        return Err(format!("Expected 32 bytes, got {}", bytes.len()));
    }
    let mut arr = [0u8; 32];
    arr.copy_from_slice(&bytes);
    Ok(arr)
}

fn decode_address(s: &str) -> Result<[u8; 20], String> {
    let bytes = decode_hex(s)?;
    if bytes.len() != 20 {
        return Err(format!("Expected 20 bytes, got {}", bytes.len()));
    }
    let mut arr = [0u8; 20];
    arr.copy_from_slice(&bytes);
    Ok(arr)
}

fn build_consent_message(
    prover_url: &str,
    registry_address: &str,
    chain_id: u64,
    registrant: &str,
    timestamp: u64,
) -> String {
    format!(
        "{}\nProver: {}\nRegistry: {}\nChain ID: {}\nWallet: {}\nTimestamp: {}",
        CONSENT_DOMAIN,
        prover_url,
        registry_address.to_lowercase(),
        chain_id,
        registrant.to_lowercase(),
        timestamp,
    )
}

/// Verify that the consent signature was produced by the certificate's private key.
fn verify_consent(
    cert_der: &[u8],
    consent_sig: &[u8],
    expected_message: &str,
) -> Result<(), String> {
    use x509_parser::prelude::FromDer;
    let (_, cert) = x509_parser::certificate::X509Certificate::from_der(cert_der)
        .map_err(|e| format!("Parse cert: {:?}", e))?;

    let prehash: [u8; 32] = Sha256::digest(expected_message.as_bytes()).into();
    let pub_key = cert.tbs_certificate.subject_pki.clone();
    let alg_oid = pub_key.algorithm.algorithm.to_id_string();

    if alg_oid == "1.2.840.113549.1.1.1" {
        // RSA
        use rsa::pkcs1v15::Pkcs1v15Sign;
        use rsa::pkcs8::DecodePublicKey;
        let rsa_pub = rsa::RsaPublicKey::from_public_key_der(pub_key.raw)
            .map_err(|e| format!("RSA parse: {}", e))?;
        rsa_pub.verify(Pkcs1v15Sign::new::<sha2::Sha256>(), &prehash, consent_sig)
            .map_err(|e| format!("RSA consent verify failed: {}", e))
    } else if alg_oid == "1.2.840.10045.2.1" {
        // ECDSA — detect curve from parameters
        let params = pub_key.algorithm.parameters.as_ref()
            .ok_or("Missing EC parameters")?;
        let curve_oid = params.as_oid()
            .map_err(|_| "Invalid EC curve OID".to_string())?
            .to_id_string();

        if curve_oid == "1.2.840.10045.3.1.7" {
            // P-256
            use p256::ecdsa::{VerifyingKey, Signature};
            use p256::ecdsa::signature::hazmat::PrehashVerifier;
            let vk = VerifyingKey::from_sec1_bytes(pub_key.subject_public_key.as_ref())
                .map_err(|e| format!("P-256 parse: {}", e))?;
            let sig = Signature::from_der(consent_sig)
                .map_err(|e| format!("P-256 sig parse: {}", e))?;
            vk.verify_prehash(&prehash, &sig)
                .map_err(|e| format!("P-256 consent verify failed: {}", e))
        } else if curve_oid == "1.3.132.0.34" {
            // P-384
            use p384::ecdsa::{VerifyingKey, Signature};
            use p384::ecdsa::signature::hazmat::PrehashVerifier;
            let vk = VerifyingKey::from_sec1_bytes(pub_key.subject_public_key.as_ref())
                .map_err(|e| format!("P-384 parse: {}", e))?;
            let sig = Signature::from_der(consent_sig)
                .map_err(|e| format!("P-384 sig parse: {}", e))?;
            vk.verify_prehash(&prehash, &sig)
                .map_err(|e| format!("P-384 consent verify failed: {}", e))
        } else {
            Err(format!("Unsupported EC curve: {}", curve_oid))
        }
    } else {
        Err(format!("Unsupported key algorithm: {}", alg_oid))
    }
}

/// Log compliance record (consent + identity mapping).
fn log_compliance(
    registrant: &str,
    cert_subject: &str,
    consent_message: &str,
    consent_sig: &str,
) {
    let log_dir = std::env::var("PROVER_LOG_DIR").unwrap_or_else(|_| "./logs".to_string());
    let _ = std::fs::create_dir_all(&log_dir);
    let timestamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs();
    let log_entry = serde_json::json!({
        "timestamp": timestamp,
        "registrant": registrant,
        "cert_subject": cert_subject,
        "consent_message": consent_message,
        "consent_signature": consent_sig,
    });
    let path = format!("{}/compliance-{}.jsonl", log_dir, timestamp / 86400);
    if let Ok(mut f) = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(&path)
    {
        use std::io::Write;
        let _ = writeln!(f, "{}", log_entry);
    }
}

// ── Handlers ────────────────────────────────────────────────────

async fn health_handler() -> Json<HealthResponse> {
    let prover_url = std::env::var("PROVER_URL")
        .unwrap_or_else(|_| "http://localhost:9090".to_string());
    Json(HealthResponse {
        status: "ok".to_string(),
        sp1_version: "v6.0.2".to_string(),
        prover_url,
    })
}

async fn prove_handler(
    Json(req): Json<DelegatedProveRequest>,
) -> Result<Json<ProveResponse>, (StatusCode, Json<ErrorResponse>)> {
    let err = |msg: String| -> (StatusCode, Json<ErrorResponse>) {
        (StatusCode::BAD_REQUEST, Json(ErrorResponse { error: msg }))
    };
    let err500 = |msg: String| -> (StatusCode, Json<ErrorResponse>) {
        (StatusCode::INTERNAL_SERVER_ERROR, Json(ErrorResponse { error: msg }))
    };

    // 1. Decode inputs
    let cert_der = decode_base64(&req.cert_der).map_err(|e| err(e))?;
    let consent_sig = decode_hex(&req.consent_signature).map_err(|e| err(e))?;
    let ownership_sig = decode_hex(&req.ownership_sig).map_err(|e| err(e))?;
    let nullifier_sig = decode_hex(&req.nullifier_sig).map_err(|e| err(e))?;
    let registrant = decode_address(&req.registrant).map_err(|e| err(e))?;
    let registry_address = decode_address(&req.registry_address).map_err(|e| err(e))?;
    let ca_merkle_root = decode_hash(&req.ca_merkle_root).map_err(|e| err(e))?;
    let ca_merkle_proof: Vec<[u8; 32]> = req.ca_merkle_proof.iter()
        .map(|s| decode_hash(s))
        .collect::<Result<Vec<_>, _>>()
        .map_err(|e| err(e))?;

    let cert_chain: Vec<Vec<u8>> = req.cert_chain.iter()
        .map(|s| decode_base64(s))
        .collect::<Result<Vec<_>, _>>()
        .map_err(|e| err(e))?;

    let crl_der = match &req.crl_data {
        Some(s) if !s.is_empty() => decode_base64(s).map_err(|e| err(e))?,
        _ => Vec::new(),
    };

    // 2. Verify consent FIRST — before any proving work
    let prover_url = std::env::var("PROVER_URL")
        .unwrap_or_else(|_| "http://localhost:9090".to_string());

    let expected_consent = build_consent_message(
        &prover_url,
        &req.registry_address,
        req.chain_id,
        &req.registrant,
        req.timestamp,
    );

    verify_consent(&cert_der, &consent_sig, &expected_consent)
        .map_err(|e| (StatusCode::FORBIDDEN, Json(ErrorResponse { error: e })))?;

    // Check consent timestamp freshness (10 minutes)
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs();
    if now.abs_diff(req.timestamp) > 600 {
        return Err(err("Consent expired (>10 min)".to_string()));
    }

    // 3. Log compliance (consent verified, identity observable)
    let cert_subject = {
        use x509_parser::prelude::FromDer;
        x509_parser::certificate::X509Certificate::from_der(&cert_der)
            .map(|(_, c)| c.subject().to_string())
            .unwrap_or_else(|_| "unknown".to_string())
    };
    log_compliance(
        &req.registrant,
        &cert_subject,
        &expected_consent,
        &req.consent_signature,
    );

    tracing::info!(
        "Proving for registrant={} cert_subject={}",
        req.registrant, cert_subject
    );

    // 4. Build SP1 stdin and generate proof
    let stdin = zk_x509_script::build_stdin(&zk_x509_script::StdinParams {
        cert_der: &cert_der,
        ownership_sig: &ownership_sig,
        nullifier_sig: &nullifier_sig,
        cert_chain: &cert_chain,
        timestamp: req.timestamp,
        crl_der: &crl_der,
        registrant: &registrant,
        wallet_index: req.wallet_index,
        max_wallets: req.max_wallets,
        disclosure_mask: req.disclosure_mask,
        ca_merkle_proof: &ca_merkle_proof,
        ca_merkle_root,
        registry_address: &registry_address,
        chain_id: req.chain_id,
    });

    // Run proving in a blocking task to avoid tokio runtime nesting
    // (SP1 ProverClient internally uses block_on which conflicts with async)
    let start = Instant::now();
    let prove_result = tokio::task::spawn_blocking(move || {
        let client = ProverClient::from_env();
        let pk = client.setup(ZK_X509_ELF)?;
        let proof: SP1ProofWithPublicValues = client
            .prove(&pk, stdin)
            .groth16()
            .run()?;
        Ok::<_, Box<dyn std::error::Error + Send>>(proof)
    })
    .await
    .map_err(|e| err500(format!("Task join error: {}", e)))?
    .map_err(|e| err500(format!("Proving failed: {}", e)))?;

    let proving_time_ms = start.elapsed().as_millis() as u64;

    // 5. Encode proof for on-chain submission
    let public_values = prove_result.public_values.as_slice().to_vec();
    let proof_bytes = prove_result.bytes();

    tracing::info!("Proof generated: proving_time={}ms", proving_time_ms);

    Ok(Json(ProveResponse {
        proof: format!("0x{}", hex::encode(&proof_bytes)),
        public_values: format!("0x{}", hex::encode(&public_values)),
        proving_time_ms,
    }))
}

// ── Main ────────────────────────────────────────────────────────

fn main() {
    sp1_sdk::utils::setup_logger();
    dotenv::dotenv().ok();

    let port = std::env::var("PROVER_PORT").unwrap_or_else(|_| "9090".to_string());
    let prover_url = std::env::var("PROVER_URL")
        .unwrap_or_else(|_| format!("http://localhost:{}", port));

    tokio::runtime::Builder::new_multi_thread()
        .enable_all()
        .build()
        .unwrap()
        .block_on(async move {
            let cors = CorsLayer::new()
                .allow_origin(AllowOrigin::any())
                .allow_methods(tower_http::cors::Any)
                .allow_headers(tower_http::cors::Any);

            let app = Router::new()
                .route("/api/prove", post(prove_handler))
                .route("/api/health", get(health_handler))
                .layer(cors)
                .layer(axum::extract::DefaultBodyLimit::max(10 * 1024 * 1024)); // 10MB

            let addr = format!("0.0.0.0:{}", port);
            tracing::info!("Delegated prover server at {}", prover_url);
            println!("Delegated prover server running at {}", prover_url);
            println!("   POST /api/prove  - Generate ZK proof (requires signed consent)");
            println!("   GET  /api/health - Server status");

            let listener = tokio::net::TcpListener::bind(&addr).await.unwrap();
            axum::serve(listener, app).await.unwrap();
        });
}
